@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@_notifications.Count</span></h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var notification in _notifications.OrderByDescending(n => n.Id))
        {
            <li class="list-group-item">
                <strong>@notification.Message</strong>
                <br />
                <small class="text-muted">@notification.Timestamp.ToString("g")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;

    protected override void OnInitialized()
    {
        // Loads during SSR so initial content is in the first HTML response.
        _notifications = NotificationService.GetAll();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires when the component is interactive in the browser.
            // This ensures the polling loop never runs during static SSR.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        // Track the highest ID we already have so we only fetch new ones.
        var lastSeenId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;

        while (!cancellationToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);

            if (cancellationToken.IsCancellationRequested)
                break;

            var newItems = NotificationService.GetSince(lastSeenId);
            if (newItems.Count > 0)
            {
                _notifications.AddRange(newItems);
                lastSeenId = newItems.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        // Clean cancellation — stops the polling loop with no leaked tasks.
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

